// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./DIDRegistry.sol";
import "./CredentialStatus.sol";

/**
 * @title AccessControl
 * @author Group 15 - CSE 540 (Revat Saharan, Abhilakshay Sreehari, Satwik Mazumdar, Sreehari Krishna Sadesh, Shashank Valayaputtur)
 * @notice Governs role-based access management within the IAM dApp.
 *         Defines and enforces the three core stakeholder roles:
 *         Issuer, Verifier, and Holder (User/Subject).
 *
 * @dev Design Rationale:
 *      - Role assignments are anchored to DIDs (not raw Ethereum addresses) to ensure
 *        that identity context is preserved even if a user rotates their keys.
 *      - The contract integrates with DIDRegistry to validate that a DID is active
 *        before granting or checking permissions.
 *      - Admins (trusted entities, e.g., universities, hospitals) can authorize Issuers.
 *      - Verifiers are self-registered but subject to Holder consent for data access.
 */
contract AccessControl {

    // -------------------------------------------------------------------------
    // Enums & Data Structures
    // -------------------------------------------------------------------------

    /// @dev The three roles in the SSI identity lifecycle.
    enum Role { NONE, HOLDER, ISSUER, VERIFIER }

    /**
     * @dev Represents a registered stakeholder in the system.
     *      did:          The DID string of this stakeholder.
     *      role:         Their assigned role (HOLDER, ISSUER, or VERIFIER).
     *      authorizedBy: The admin address that granted ISSUER role (zero for others).
     *      registeredAt: Block timestamp of role registration.
     *      active:       Whether this stakeholder is currently active.
     */
    struct Stakeholder {
        string did;
        Role role;
        address authorizedBy;
        uint256 registeredAt;
        bool active;
    }

    /**
     * @dev Represents a Holder's consent grant to a specific Verifier.
     *      holderDID:    The DID of the consenting Holder.
     *      verifierDID:  The DID of the Verifier being granted access.
     *      credentialId: The specific credential the Verifier may access.
     *      expiresAt:    Timestamp after which the consent is no longer valid (0 = no expiry).
     *      granted:      Whether the consent is currently active.
     */
    struct ConsentGrant {
        string holderDID;
        string verifierDID;
        bytes32 credentialId;
        uint256 expiresAt;
        bool granted;
    }

    // -------------------------------------------------------------------------
    // State Variables
    // -------------------------------------------------------------------------

    /// @dev Reference to the DIDRegistry contract for DID resolution and validation.
    DIDRegistry public immutable didRegistry;

    /// @dev Reference to the CredentialStatus contract for revocation checks.
    CredentialStatus public immutable credentialStatus;

    /// @dev The deployer address is the initial super-admin of this access control system.
    address public immutable superAdmin;

    /// @dev Maps Ethereum address => Stakeholder record.
    mapping(address => Stakeholder) private stakeholders;

    /// @dev Maps an admin address to whether they have admin privileges.
    mapping(address => bool) private admins;

    /**
     * @dev Consent registry. Key is keccak256(holderDID, verifierDID, credentialId).
     *      Allows holders to grant/revoke per-credential access to specific verifiers.
     */
    mapping(bytes32 => ConsentGrant) private consentGrants;

    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a new stakeholder is registered with a role.
    event StakeholderRegistered(address indexed account, string did, Role role, uint256 timestamp);

    /// @notice Emitted when an admin authorizes a new Issuer.
    event IssuerAuthorized(address indexed issuer, string did, address indexed admin, uint256 timestamp);

    /// @notice Emitted when a Holder grants consent to a Verifier for a specific credential.
    event ConsentGranted(string holderDID, string verifierDID, bytes32 credentialId, uint256 expiresAt);

    /// @notice Emitted when a Holder revokes a previously granted consent.
    event ConsentRevoked(string holderDID, string verifierDID, bytes32 credentialId, uint256 timestamp);

    // -------------------------------------------------------------------------
    // Constructor
    // -------------------------------------------------------------------------

    /**
     * @param _didRegistry        Address of the deployed DIDRegistry contract.
     * @param _credentialStatus   Address of the deployed CredentialStatus contract.
     */
    constructor(address _didRegistry, address _credentialStatus) {
        didRegistry = DIDRegistry(_didRegistry);
        credentialStatus = CredentialStatus(_credentialStatus);
        superAdmin = msg.sender;
        admins[msg.sender] = true;
    }

    // -------------------------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------------------------

    /// @dev Restricts access to admins only.
    modifier onlyAdmin() {
        require(admins[msg.sender], "AccessControl: Caller is not an admin");
        _;
    }

    /// @dev Ensures the caller is a registered active stakeholder.
    modifier onlyRegistered() {
        require(stakeholders[msg.sender].active, "AccessControl: Caller is not registered");
        _;
    }

    // -------------------------------------------------------------------------
    // Role Management Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Registers the caller as a Holder in the system.
     * @dev    Requires that the caller has an active DID in the DIDRegistry.
     *         Holders self-register; no admin approval is needed.
     * @param did  The caller's DID string (must be active in DIDRegistry).
     */
    function registerAsHolder(string memory did) external {
        // TODO: Implement Holder registration
        // - Verify didRegistry.isDIDActive(did) is true
        // - Verify msg.sender is not already registered (stakeholders[msg.sender].active == false)
        // - Create a Stakeholder record with Role.HOLDER and store in stakeholders[msg.sender]
        // - Emit StakeholderRegistered event
    }

    /**
     * @notice Registers the caller as a Verifier in the system.
     * @dev    Verifiers self-register but require an active DID.
     *         They can only access credentials with explicit Holder consent.
     * @param did  The caller's DID string (must be active in DIDRegistry).
     */
    function registerAsVerifier(string memory did) external {
        // TODO: Implement Verifier registration
        // - Similar to registerAsHolder but with Role.VERIFIER
        // - Emit StakeholderRegistered event
    }

    /**
     * @notice Authorizes a specific address as an Issuer. Admin-only.
     * @dev    Issuers are trusted entities (e.g., universities, hospitals) granted by admins.
     * @param issuerAddress  The Ethereum address of the entity to authorize as Issuer.
     * @param did            The Issuer's active DID.
     */
    function authorizeIssuer(address issuerAddress, string memory did) external onlyAdmin {
        // TODO: Implement Issuer authorization
        // - Verify didRegistry.isDIDActive(did) is true
        // - Create/update the Stakeholder record for issuerAddress with Role.ISSUER
        // - Set authorizedBy = msg.sender
        // - Emit IssuerAuthorized event
    }

    // -------------------------------------------------------------------------
    // Consent Management Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Grants a specific Verifier access to a specific credential.
     * @dev    Called by a Holder to authorize a Verifier to view a credential.
     *         Consent is scoped to a single credentialId to enforce data minimization.
     * @param verifierDID   The DID of the Verifier being granted access.
     * @param credentialId  The specific credential being consented to.
     * @param expiresAt     Unix timestamp for consent expiry (0 for no expiry).
     */
    function grantConsent(
        string memory verifierDID,
        bytes32 credentialId,
        uint256 expiresAt
    ) external onlyRegistered {
        // TODO: Implement consent granting
        // - Retrieve caller's DID from stakeholders[msg.sender].did
        // - Generate consentKey = keccak256(abi.encodePacked(holderDID, verifierDID, credentialId))
        // - Store ConsentGrant in consentGrants[consentKey]
        // - Emit ConsentGranted event
    }

    /**
     * @notice Revokes a previously granted consent.
     * @dev    Called by a Holder to withdraw a Verifier's access to a credential.
     * @param verifierDID   The DID of the Verifier whose access is being revoked.
     * @param credentialId  The credential for which consent is revoked.
     */
    function revokeConsent(string memory verifierDID, bytes32 credentialId) external onlyRegistered {
        // TODO: Implement consent revocation
        // - Compute consentKey
        // - Set consentGrants[consentKey].granted = false
        // - Emit ConsentRevoked event
    }

    // -------------------------------------------------------------------------
    // View / Read Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Returns the role of a given Ethereum address.
     * @param account  The address to query.
     * @return         The Role enum value (NONE, HOLDER, ISSUER, or VERIFIER).
     */
    function getRole(address account) external view returns (Role) {
        return stakeholders[account].role;
    }

    /**
     * @notice Checks whether a Verifier has valid consent to access a specific credential.
     * @param holderDID     The DID of the Holder who issued the consent.
     * @param verifierDID   The DID of the Verifier requesting access.
     * @param credentialId  The credential being accessed.
     * @return              True if consent is granted and not expired.
     */
    function hasConsent(
        string memory holderDID,
        string memory verifierDID,
        bytes32 credentialId
    ) external view returns (bool) {
        // TODO: Implement consent check
        // - Compute consentKey
        // - Retrieve the ConsentGrant
        // - Return grant.granted && (grant.expiresAt == 0 || block.timestamp <= grant.expiresAt)
        revert("AccessControl: hasConsent not implemented");
    }

    /**
     * @notice Returns the full Stakeholder record for a given address.
     * @param account  The Ethereum address to query.
     * @return         The Stakeholder struct with DID, role, and registration details.
     */
    function getStakeholder(address account) external view returns (Stakeholder memory) {
        return stakeholders[account];
    }
}

contracts/CredentialStatus.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title CredentialStatus
 * @author Group 15 - CSE 540 (Revat Saharan, Abhilakshay Sreehari, Satwik Mazumdar, Sreehari Krishna Sadesh, Shashank Valayaputtur)
 * @notice Manages the on-chain revocation and status registry for Verifiable Credentials (VCs).
 *         Uses a gas-efficient bitmap approach: each credential is assigned an index in a
 *         bitmap, and its revocation status is stored as a single bit flip.
 *
 * @dev Design Rationale:
 *      - Storing full VCs on-chain is gas-prohibitive and risks PII exposure.
 *      - Instead, only a cryptographic hash (commitment) of each VC is anchored here.
 *      - Verifiers fetch the full VC from IPFS, recompute the hash, and compare it to
 *        the on-chain commitment to verify data integrity.
 *      - The bitmap revocation list allows O(1) status checks with minimal gas overhead.
 *      - Complies with the W3C StatusList2021 specification concept.
 */
contract CredentialStatus {

    // -------------------------------------------------------------------------
    // Data Structures
    // -------------------------------------------------------------------------

    /**
     * @dev On-chain anchor record for an issued Verifiable Credential.
     *      issuer:          The Ethereum address (DID controller) that issued the credential.
     *      subjectDID:      The DID of the credential subject (holder).
     *      credentialHash:  Keccak256 hash of the off-chain VC JSON payload (integrity anchor).
     *      ipfsCID:         The IPFS Content Identifier where the encrypted VC is stored.
     *      issuedAt:        Block timestamp when the credential anchor was written on-chain.
     *      statusIndex:     The index of this credential in the issuer's revocation bitmap.
     */
    struct CredentialAnchor {
        address issuer;
        string subjectDID;
        bytes32 credentialHash;
        string ipfsCID;
        uint256 issuedAt;
        uint256 statusIndex;
    }

    // -------------------------------------------------------------------------
    // State Variables
    // -------------------------------------------------------------------------

    /// @dev Maps a credential ID (bytes32 hash of issuer+subject+nonce) to its on-chain anchor.
    mapping(bytes32 => CredentialAnchor) private credentialAnchors;

    /// @dev Tracks which credential IDs have been registered.
    mapping(bytes32 => bool) private registeredCredentials;

    /**
     * @dev Bitmap-based revocation list.
     *      revocationBitmaps[issuer][bitmapChunk] is a uint256 where each bit
     *      represents the revocation status of one credential (1 = revoked, 0 = valid).
     *      This allows 256 credentials per storage slot, minimizing gas costs.
     */
    mapping(address => mapping(uint256 => uint256)) private revocationBitmaps;

    /// @dev Tracks the next available status index per issuer for bitmap allocation.
    mapping(address => uint256) private nextStatusIndex;

    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a new credential anchor is written on-chain by an issuer.
    event CredentialIssued(
        bytes32 indexed credentialId,
        address indexed issuer,
        string indexed subjectDID,
        bytes32 credentialHash,
        string ipfsCID,
        uint256 statusIndex,
        uint256 timestamp
    );

    /// @notice Emitted when an issuer revokes a previously issued credential.
    event CredentialRevoked(
        bytes32 indexed credentialId,
        address indexed issuer,
        uint256 statusIndex,
        uint256 timestamp
    );

    /// @notice Emitted when a verifier triggers an on-chain verification event (for auditability).
    event VerificationLogged(
        bytes32 indexed credentialId,
        address indexed verifier,
        bool result,
        uint256 timestamp
    );

    // -------------------------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------------------------

    /// @dev Restricts revocation to the original issuer of a credential.
    modifier onlyIssuer(bytes32 credentialId) {
        require(registeredCredentials[credentialId], "CredentialStatus: Credential not found");
        require(
            credentialAnchors[credentialId].issuer == msg.sender,
            "CredentialStatus: Caller is not the issuer"
        );
        _;
    }

    // -------------------------------------------------------------------------
    // Core Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Anchors a new Verifiable Credential on-chain after off-chain signing.
     * @dev    Called by the Issuer after signing the VC off-chain with EIP-712.
     *         Only the IPFS CID and credential hash are stored — no raw credential data.
     *         Automatically allocates a status bitmap index for future revocation.
     * @param subjectDID      The DID of the credential subject (holder).
     * @param credentialHash  Keccak256 hash of the full VC JSON payload.
     * @param ipfsCID         The IPFS CID pointing to the encrypted VC off-chain.
     * @return credentialId   A unique bytes32 identifier for this credential anchor.
     */
    function issueCredential(
        string memory subjectDID,
        bytes32 credentialHash,
        string memory ipfsCID
    ) external returns (bytes32 credentialId) {
        credentialId = keccak256(
            abi.encodePacked(msg.sender, subjectDID, credentialHash, block.timestamp)
        );
        require(!registeredCredentials[credentialId], "CredentialStatus: duplicate credentialId");

        uint256 statusIndex = nextStatusIndex[msg.sender];
        unchecked {
            nextStatusIndex[msg.sender] = statusIndex + 1;
        }

        credentialAnchors[credentialId] = CredentialAnchor({
            issuer: msg.sender,
            subjectDID: subjectDID,
            credentialHash: credentialHash,
            ipfsCID: ipfsCID,
            issuedAt: block.timestamp,
            statusIndex: statusIndex
        });
        registeredCredentials[credentialId] = true;

        emit CredentialIssued(
            credentialId,
            msg.sender,
            subjectDID,
            credentialHash,
            ipfsCID,
            statusIndex,
            block.timestamp
        );
    }

    /**
     * @notice Revokes an existing credential by flipping its bit in the revocation bitmap.
     * @dev    Only the original issuer may revoke. Sets the bit at statusIndex to 1.
     *         This is a gas-efficient O(1) operation using bitwise OR.
     * @param credentialId  The unique identifier of the credential anchor to revoke.
     */
    function revokeCredential(bytes32 credentialId) external onlyIssuer(credentialId) {
        // TODO: Implement revocation logic
        // - Retrieve the credential's statusIndex from credentialAnchors[credentialId]
        // - Compute bitmapChunk = statusIndex / 256 and bitPosition = statusIndex % 256
        // - Set the bit: revocationBitmaps[msg.sender][bitmapChunk] |= (1 << bitPosition)
        // - Emit CredentialRevoked event
    }

    /**
     * @notice Logs a verification attempt on-chain for auditability.
     * @dev    Does not enforce access; purely an event-emission for transparency.
     *         Verifiers call this to leave an immutable audit trail without PII.
     * @param credentialId  The credential being verified.
     * @param result        The result of the off-chain cryptographic verification.
     */
    function logVerification(bytes32 credentialId, bool result) external {
        require(registeredCredentials[credentialId], "CredentialStatus: Credential not found");
        emit VerificationLogged(credentialId, msg.sender, result, block.timestamp);
    }

    // -------------------------------------------------------------------------
    // View / Read Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Checks whether a credential has been revoked.
     * @dev    Reads the bitmap bit at the credential's statusIndex.
     * @param credentialId  The unique identifier of the credential to check.
     * @return              True if the credential has been revoked, false if still valid.
     */
    function isRevoked(bytes32 credentialId) external view returns (bool) {
        require(registeredCredentials[credentialId], "CredentialStatus: Credential not found");
        CredentialAnchor storage anchor = credentialAnchors[credentialId];
        uint256 statusIndex = anchor.statusIndex;
        address issuer = anchor.issuer;
        uint256 bitmapChunk = statusIndex / 256;
        uint256 bitPosition = statusIndex % 256;
        uint256 chunk = revocationBitmaps[issuer][bitmapChunk];
        return ((chunk >> bitPosition) & 1) == 1;
    }

    /**
     * @notice Returns the on-chain anchor data for a given credential ID.
     * @param credentialId  The unique identifier of the credential to retrieve.
     * @return              The CredentialAnchor struct with IPFS CID, hash, and metadata.
     */
    function getCredentialAnchor(bytes32 credentialId) external view returns (CredentialAnchor memory) {
        require(registeredCredentials[credentialId], "CredentialStatus: Credential not found");
        return credentialAnchors[credentialId];
    }

    /**
     * @notice Verifies the integrity of a fetched VC by comparing its hash to the on-chain commitment.
     * @dev    Verifiers fetch the encrypted VC from IPFS, decrypt it, then call this to confirm
     *         the data has not been tampered with.
     * @param credentialId    The credential anchor ID to verify against.
     * @param computedHash    The keccak256 hash of the locally fetched and decrypted VC payload.
     * @return                True if the hash matches the on-chain commitment (data integrity confirmed).
     */
    function verifyCredentialIntegrity(bytes32 credentialId, bytes32 computedHash) external view returns (bool) {
        require(registeredCredentials[credentialId], "CredentialStatus: Credential not found");
        return credentialAnchors[credentialId].credentialHash == computedHash;
    }
}

contracts/DIDRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title DIDRegistry
 * @author Group 15 - CSE 540 (Revat Saharan, Abhilakshay Sreehari, Satwik Mazumdar, Sreehari Krishna Sadesh, Shashank Valayaputtur)
 * @notice Implements a W3C-compliant Decentralized Identifier (DID) registry on-chain.
 *         This contract anchors minimal DID metadata (public keys, service endpoints,
 *         and controller addresses) without ever storing raw PII on the ledger.
 *
 * @dev Architecture Overview:
 *      - Each DID maps to a DIDDocument struct holding key references and service endpoints.
 *      - All mutations emit events for transparent, immutable auditability.
 *      - Only the DID controller (owner) may update or deactivate their DID document.
 *      - Follows the W3C DID Core spec: https://www.w3.org/TR/did-core/
 */
contract DIDRegistry {

    // -------------------------------------------------------------------------
    // Data Structures
    // -------------------------------------------------------------------------

    /**
     * @dev Represents a public key associated with a DID.
     *      keyId:       A short identifier for this key (e.g., "key-1").
     *      keyType:     The cryptographic key type (e.g., "EcdsaSecp256k1VerificationKey2019").
     *      controller:  The DID that controls this key.
     *      publicKeyHex: The hex-encoded public key material.
     */
    struct PublicKey {
        string keyId;
        string keyType;
        address controller;
        string publicKeyHex;
    }

    /**
     * @dev Represents a service endpoint in the DID document.
     *      serviceId:   A short identifier for this service (e.g., "LinkedDomains").
     *      serviceType: The type of service (e.g., "VerifiableCredentialService").
     *      endpoint:    The URL or URI of the service.
     */
    struct ServiceEndpoint {
        string serviceId;
        string serviceType;
        string endpoint;
    }

    /**
     * @dev The on-chain DID Document. Stores only metadata anchors, never raw PII.
     *      controller:        The Ethereum address that owns and controls this DID.
     *      created:           Block timestamp of DID registration.
     *      updated:           Block timestamp of the last update.
     *      active:            Whether the DID is currently active (not deactivated).
     *      publicKeys:        Array of cryptographic keys associated with this DID.
     *      serviceEndpoints:  Array of service endpoints declared in the DID document.
     */
    struct DIDDocument {
        address controller;
        uint256 created;
        uint256 updated;
        bool active;
        PublicKey[] publicKeys;
        ServiceEndpoint[] serviceEndpoints;
    }

    // -------------------------------------------------------------------------
    // State Variables
    // -------------------------------------------------------------------------

    /// @dev Maps a DID string (e.g., "did:ethr:0x...") to its on-chain DID document.
    mapping(string => DIDDocument) private didDocuments;

    /// @dev Tracks which DIDs have been registered to prevent duplicates.
    mapping(string => bool) private registeredDIDs;

    /// @dev Maps an Ethereum address to the DIDs it controls (for lookup convenience).
    mapping(address => string[]) private controllerToDIDs;

    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a new DID is registered on-chain.
    event DIDRegistered(string indexed did, address indexed controller, uint256 timestamp);

    /// @notice Emitted when a DID document is updated (key or service change).
    event DIDUpdated(string indexed did, address indexed controller, uint256 timestamp);

    /// @notice Emitted when a DID is deactivated by its controller.
    event DIDDeactivated(string indexed did, address indexed controller, uint256 timestamp);

    // -------------------------------------------------------------------------
    // Modifiers
    // -------------------------------------------------------------------------

    /// @dev Restricts a function to the controller of a given DID.
    modifier onlyController(string memory did) {
        require(registeredDIDs[did], "DIDRegistry: DID not registered");
        require(didDocuments[did].controller == msg.sender, "DIDRegistry: Caller is not controller");
        require(didDocuments[did].active, "DIDRegistry: DID has been deactivated");
        _;
    }

    // -------------------------------------------------------------------------
    // Core Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Registers a new Decentralized Identifier (DID) on-chain.
     * @dev    Anchors the DID to the caller's address as the controller.
     *         The full DID document (credentials, extended metadata) is stored
     *         off-chain (IPFS); only the minimal anchor is stored here.
     * @param did              The DID string to register (e.g., "did:ethr:0x...").
     * @param initialPublicKey The primary verification key to associate with this DID.
     * @param initialService   An optional initial service endpoint (pass empty strings to skip).
     */
    function registerDID(
        string memory did,
        PublicKey memory initialPublicKey,
        ServiceEndpoint memory initialService
    ) external {
        require(bytes(did).length > 0, "DIDRegistry: empty DID");
        require(!registeredDIDs[did], "DIDRegistry: DID already registered");

        DIDDocument storage doc = didDocuments[did];
        doc.controller = msg.sender;
        doc.created = block.timestamp;
        doc.updated = block.timestamp;
        doc.active = true;
        doc.publicKeys.push(initialPublicKey);
        if (bytes(initialService.serviceId).length > 0) {
            doc.serviceEndpoints.push(initialService);
        }

        registeredDIDs[did] = true;
        controllerToDIDs[msg.sender].push(did);

        emit DIDRegistered(did, msg.sender, block.timestamp);
    }

    /**
     * @notice Adds a new public key to an existing DID document.
     * @dev    Only the DID controller may call this. Emits DIDUpdated.
     * @param did       The DID to update.
     * @param newKey    The new PublicKey struct to append to the DID document.
     */
    function addPublicKey(string memory did, PublicKey memory newKey) external onlyController(did) {
        // TODO: Implement key addition logic
        // - Push newKey into didDocuments[did].publicKeys
        // - Update the `updated` timestamp
        // - Emit DIDUpdated event
    }

    /**
     * @notice Adds a new service endpoint to an existing DID document.
     * @dev    Only the DID controller may call this. Emits DIDUpdated.
     * @param did      The DID to update.
     * @param service  The new ServiceEndpoint struct to append.
     */
    function addServiceEndpoint(string memory did, ServiceEndpoint memory service) external onlyController(did) {
        // TODO: Implement service endpoint addition logic
        // - Push service into didDocuments[did].serviceEndpoints
        // - Update the `updated` timestamp
        // - Emit DIDUpdated event
    }

    /**
     * @notice Permanently deactivates a DID. This action is irreversible.
     * @dev    Sets active = false. The DID document remains readable for historical audit.
     *         Only the DID controller may call this. Emits DIDDeactivated.
     * @param did  The DID to deactivate.
     */
    function deactivateDID(string memory did) external onlyController(did) {
        // TODO: Implement deactivation logic
        // - Set didDocuments[did].active = false
        // - Update the `updated` timestamp
        // - Emit DIDDeactivated event
    }

    // -------------------------------------------------------------------------
    // View / Read Functions
    // -------------------------------------------------------------------------

    /**
     * @notice Resolves a DID to its on-chain document metadata.
     * @param did  The DID string to resolve.
     * @return     The DIDDocument struct associated with the given DID.
     */
    function resolveDID(string memory did) external view returns (DIDDocument memory) {
        require(registeredDIDs[did], "DIDRegistry: DID not registered");
        return didDocuments[did];
    }

    /**
     * @notice Returns all DIDs controlled by a given Ethereum address.
     * @param controller  The controller address to query.
     * @return            An array of DID strings controlled by the address.
     */
    function getDIDsByController(address controller) external view returns (string[] memory) {
        return controllerToDIDs[controller];
    }

    /**
     * @notice Checks whether a given DID is currently active.
     * @param did  The DID string to check.
     * @return     True if the DID is registered and active, false otherwise.
     */
    function isDIDActive(string memory did) external view returns (bool) {
        if (!registeredDIDs[did]) return false;
        return didDocuments[did].active;
    }
}

